#!/usr/bin/env bash
set -euo pipefail
source "$(dirname "$0")/lib/common.sh"
serial=emulator-5554; apk=; skip_install=false; while (($#)); do case "$1" in --serial) serial="${2:?}"; shift 2;; --apk) apk="${2:?}"; shift 2;; --skip-install) skip_install=true; shift;; *) archphene_die "unknown argument: $1";; esac; done; apk="${apk:-$ARCHPHENE_ROOT/tooling/build/terminal-prompt/archphene-terminal.apk}"; package=org.archpheneos.terminal; archphene_init_adb "$serial"; [[ "$(archphene_adb_run get-state | tr -d '\r')" == device ]] || archphene_die "device $serial is not ready"; if [[ "$skip_install" == false ]]; then archphene_require_file "$apk"; archphene_adb_run install -r "$apk" >/dev/null; fi; archphene_adb_run shell run-as "$package" mkdir -p files/terminal/home/Documents/source/ArchpheneOS
probe(){ local command="$1" encoded deadline log; encoded="$(printf %s "$command" | base64 -w0)"; archphene_adb_run shell am force-stop "$package"; archphene_adb_run logcat -c; archphene_adb_run shell am start -W -n "$package/.TerminalActivity" --ei archphene_test_terminal_send_delay_ms 3000 --ei archphene_test_terminal_capture_delay_ms 3000 --es archphene_test_terminal_command_base64 "$encoded" >/dev/null; deadline=$((SECONDS+15)); while ((SECONDS<deadline)); do sleep 1; log="$(archphene_adb_run logcat -d -v brief -s ArchpheneTerminal:I '*:S')"; [[ "$log" == *'Terminal command probe transcript='* ]] && { printf %s "$log"; return; }; done; archphene_die 'timed out waiting for Terminal prompt probe'; }
home="$(probe 'echo HOME_PROMPT_OK')"; archphene_regex_contains "$home" '(?m): \$ echo HOME_PROMPT_OK\r?$' || archphene_die 'submitted command was not retained'; archphene_regex_contains "$home" '(?m): HOME_PROMPT_OK\r?$' || archphene_die 'submitted command did not execute'; archphene_regex_contains "$home" '(?m): archphene ~\r?$' || archphene_die 'home prompt was not abbreviated'; [[ "$(grep -c ': archphene ' <<<"$home")" == 1 ]] || archphene_die 'submitted prompt context was not collapsed'; nested="$(probe 'cd ~/Documents/source/ArchpheneOS')"; archphene_regex_contains "$nested" '(?m): \$ cd ~/Documents/source/ArchpheneOS\r?$' || archphene_die 'nested command not retained'; archphene_regex_contains "$nested" '(?m): archphene ~/D/s/ArchpheneOS\r?$' || archphene_die 'fish-style path abbreviation not rendered'; [[ "$nested" != *'Shell marker='* ]] || archphene_die 'diagnostic shell marker remains enabled'; archphene_note "Terminal transient two-line prompt passed on $serial."
